def path_url(self):
    """Build the path URL to use."""

    url = []

    p = urlsplit(self.url)

    path = p.path
    if not path:
        path = "/"

    url.append(path)

    query = p.query
    if query:
        url.append("?")
        url.append(query)

    return "".join(url)

