import pytest
from urllib.parse import urlsplit

class TestPathUrl:
    def test_normal_url_with_path(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path/to/resource'})()
        assert obj.path_url() == '/path/to/resource'

    def test_normal_url_without_path(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com'})()
        assert obj.path_url() == '/'

    def test_url_with_query_parameters(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path?param1=value1&param2=value2'})()
        assert obj.path_url() == '/path?param1=value1&param2=value2'

    def test_url_with_empty_query(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path?'})()
        assert obj.path_url() == '/path?'

    def test_url_with_only_query(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/?param=value'})()
        assert obj.path_url() == '/?param=value'

    def test_url_with_trailing_slash(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path/'})()
        assert obj.path_url() == '/path/'

    def test_url_with_encoded_characters(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path/to/resource%20with%20spaces?param=value'})()
        assert obj.path_url() == '/path/to/resource%20with%20spaces?param=value'

    def test_url_with_no_scheme(self):
        obj = type('TestObj', (object,), {'url': 'example.com/path'})()
        assert obj.path_url() == '/path'

    def test_url_with_invalid_url(self):
        obj = type('TestObj', (object,), {'url': 'http://%20invalid.url'})()
        assert obj.path_url() == '/'

    def test_url_with_special_characters(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path/to/resource@#&$'})()
        assert obj.path_url() == '/path/to/resource@#&$'

    def test_url_with_empty_string(self):
        obj = type('TestObj', (object,), {'url': ''})()
        assert obj.path_url() == '/'

    def test_url_with_none(self):
        obj = type('TestObj', (object,), {'url': None})()
        with pytest.raises(AttributeError):
            obj.path_url()

