import pytest

class TestDeregisterHook:
    class MockClass:
        def __init__(self):
            self.hooks = {
                'event1': ['hook1', 'hook2'],
                'event2': ['hook3'],
            }

        def deregister_hook(self, event, hook):
            """Deregister a previously registered hook.
            Returns True if the hook existed, False if not.
            """
            try:
                self.hooks[event].remove(hook)
                return True
            except ValueError:
                return False

    def setup_method(self):
        self.mock_instance = self.MockClass()

    def test_deregister_existing_hook(self):
        result = self.mock_instance.deregister_hook('event1', 'hook1')
        assert result is True
        assert 'hook1' not in self.mock_instance.hooks['event1']

    def test_deregister_non_existing_hook(self):
        result = self.mock_instance.deregister_hook('event1', 'hook3')
        assert result is False
        assert 'hook1' in self.mock_instance.hooks['event1']
        assert 'hook2' in self.mock_instance.hooks['event1']

    def test_deregister_hook_from_non_existing_event(self):
        result = self.mock_instance.deregister_hook('event3', 'hook1')
        assert result is False

    def test_deregister_hook_when_hooks_list_is_empty(self):
        self.mock_instance.hooks['event2'] = []
        result = self.mock_instance.deregister_hook('event2', 'hook3')
        assert result is False

    def test_deregister_hook_case_sensitivity(self):
        result = self.mock_instance.deregister_hook('event1', 'Hook1')
        assert result is False
        assert 'hook1' in self.mock_instance.hooks['event1']

    def test_deregister_hook_multiple_times(self):
        self.mock_instance.deregister_hook('event1', 'hook1')
        result = self.mock_instance.deregister_hook('event1', 'hook1')
        assert result is False

    def test_deregister_hook_with_different_event(self):
        result = self.mock_instance.deregister_hook('event1', 'hook2')
        assert result is True
        assert 'hook2' not in self.mock_instance.hooks['event1']
        assert 'hook3' in self.mock_instance.hooks['event2']

    def test_deregister_hook_with_none(self):
        result = self.mock_instance.deregister_hook('event1', None)
        assert result is False

    def test_deregister_hook_with_empty_string(self):
        result = self.mock_instance.deregister_hook('event1', '')
        assert result is False

