import pytest
import cookielib
from unittest.mock import Mock

# Assuming the class containing prepare_cookies is named PreparedRequest
from your_module import PreparedRequest, cookiejar_from_dict, get_cookie_header

@pytest.fixture
def prepared_request():
    return PreparedRequest()

def test_prepare_cookies_with_cookiejar(prepared_request):
    cookie_jar = cookielib.CookieJar()
    prepared_request.prepare_cookies(cookie_jar)
    assert prepared_request._cookies is cookie_jar

def test_prepare_cookies_with_dict(prepared_request):
    cookies_dict = {'session_id': 'abc123', 'user_id': 'user42'}
    prepared_request.prepare_cookies(cookies_dict)
    assert isinstance(prepared_request._cookies, cookielib.CookieJar)

def test_prepare_cookies_header_set(prepared_request, monkeypatch):
    cookies_dict = {'session_id': 'abc123'}
    monkeypatch.setattr('your_module.get_cookie_header', lambda x, y: 'session_id=abc123')
    prepared_request.prepare_cookies(cookies_dict)
    assert prepared_request.headers["Cookie"] == 'session_id=abc123'

def test_prepare_cookies_no_header_if_none(prepared_request, monkeypatch):
    cookies_dict = {'session_id': 'abc123'}
    monkeypatch.setattr('your_module.get_cookie_header', lambda x, y: None)
    prepared_request.prepare_cookies(cookies_dict)
    assert "Cookie" not in prepared_request.headers

def test_prepare_cookies_called_twice(prepared_request, monkeypatch):
    cookies_dict = {'session_id': 'abc123'}
    monkeypatch.setattr('your_module.get_cookie_header', lambda x, y: 'session_id=abc123')
    prepared_request.prepare_cookies(cookies_dict)
    prepared_request.prepare_cookies(cookies_dict)  # Call again
    assert prepared_request.headers["Cookie"] == 'session_id=abc123'

def test_prepare_cookies_with_empty_dict(prepared_request):
    cookies_dict = {}
    prepared_request.prepare_cookies(cookies_dict)
    assert isinstance(prepared_request._cookies, cookielib.CookieJar)
    assert "Cookie" not in prepared_request.headers

def test_prepare_cookies_with_invalid_type(prepared_request):
    with pytest.raises(TypeError):
        prepared_request.prepare_cookies(123)

def test_prepare_cookies_with_none(prepared_request):
    prepared_request.prepare_cookies(None)
    assert isinstance(prepared_request._cookies, cookielib.CookieJar)
    assert "Cookie" not in prepared_request.headers

