import pytest

class MockResponse:
    def __init__(self, status_code, raw, content_consumed=False):
        self.status_code = status_code
        self.raw = raw
        self._content = False
        self._content_consumed = content_consumed

    def iter_content(self, chunk_size):
        if self.raw is None:
            return []
        return [self.raw[i:i + chunk_size] for i in range(0, len(self.raw), chunk_size)]

CONTENT_CHUNK_SIZE = 1024

def test_content_normal_case():
    response = MockResponse(200, b"Hello, World!")
    assert response.content() == b"Hello, World!"

def test_content_empty_response():
    response = MockResponse(200, b"")
    assert response.content() == b""

def test_content_none_raw():
    response = MockResponse(200, None)
    assert response.content() is None

def test_content_status_code_zero():
    response = MockResponse(0, b"Hello")
    assert response.content() is None

def test_content_already_consumed():
    response = MockResponse(200, b"Hello, World!", content_consumed=True)
    with pytest.raises(RuntimeError, match="The content for this response was already consumed"):
        response.content()

def test_content_large_data():
    large_data = b"x" * (CONTENT_CHUNK_SIZE * 10)
    response = MockResponse(200, large_data)
    assert response.content() == large_data

def test_content_consumed_flag():
    response = MockResponse(200, b"Hello")
    assert not response._content_consumed
    response.content()
    assert response._content_consumed

def test_content_with_none_raw_and_consumed():
    response = MockResponse(200, None, content_consumed=True)
    assert response.content() is None

