import pytest

class MockResponse:
    def __init__(self, content, encoding=None, apparent_encoding=None):
        self.content = content
        self.encoding = encoding
        self.apparent_encoding = apparent_encoding

    def text(self):
        content = None
        encoding = self.encoding

        if not self.content:
            return ""

        if self.encoding is None:
            encoding = self.apparent_encoding

        try:
            content = str(self.content, encoding, errors="replace")
        except (LookupError, TypeError):
            content = str(self.content, errors="replace")

        return content

def test_text_normal_case_utf8():
    response = MockResponse(b'Hello, world!', encoding='utf-8')
    assert response.text() == 'Hello, world!'

def test_text_normal_case_iso88591():
    response = MockResponse(b'Bonjour, le monde!', encoding='iso-8859-1')
    assert response.text() == 'Bonjour, le monde!'

def test_text_empty_content():
    response = MockResponse(b'')
    assert response.text() == ''

def test_text_none_content():
    response = MockResponse(None)
    assert response.text() == ''

def test_text_auto_detect_encoding():
    response = MockResponse(b'\xe9', apparent_encoding='utf-8')
    assert response.text() == 'é'

def test_text_invalid_encoding():
    response = MockResponse(b'Hello, world!', encoding='invalid-encoding')
    assert response.text() == 'Hello, world!'  # Should fallback to replace

def test_text_type_error_on_encoding():
    response = MockResponse(b'Hello, world!', encoding=None)
    assert response.text() == 'Hello, world!'  # Should fallback to replace

def test_text_with_replacement_characters():
    response = MockResponse(b'\xff\xfe\xfd', encoding='utf-8')
    assert response.text() == '�' * 3  # Replacement character for invalid bytes

def test_text_with_mixed_content():
    response = MockResponse(b'Hello, \xe9', encoding='utf-8')
    assert response.text() == 'Hello, é'

def test_text_with_non_bytes_content():
    response = MockResponse('Hello, world!', encoding='utf-8')
    assert response.text() == 'Hello, world!'  # Should handle str input

def test_text_with_non_bytes_content_none_encoding():
    response = MockResponse('Hello, world!')
    assert response.text() == 'Hello, world!'  # Should handle str input without encoding

