import pytest

class TestFormatTimeframe:
    class MockClass:
        timeframes = {
            'days': {
                'future': "in {} days",
                'past': "{} days ago"
            },
            'hours': {
                'future': "in {} hours",
                'past': "{} hours ago"
            },
            'minutes': "just {} minutes"
        }

        def _format_timeframe(self, timeframe, delta):
            abs_delta = abs(delta)
            form = self.timeframes[timeframe]

            if isinstance(form, str):
                return form.format(abs_delta)

            if delta > 0:
                key = "future"
            else:
                key = "past"
            form = form[key]

            return form.format(abs_delta)

    def setup_method(self):
        self.mock_instance = self.MockClass()

    def test_format_timeframe_future_days(self):
        result = self.mock_instance._format_timeframe('days', 5)
        assert result == "in 5 days"

    def test_format_timeframe_past_days(self):
        result = self.mock_instance._format_timeframe('days', -3)
        assert result == "3 days ago"

    def test_format_timeframe_future_hours(self):
        result = self.mock_instance._format_timeframe('hours', 2)
        assert result == "in 2 hours"

    def test_format_timeframe_past_hours(self):
        result = self.mock_instance._format_timeframe('hours', -1)
        assert result == "1 hour ago"

    def test_format_timeframe_minutes(self):
        result = self.mock_instance._format_timeframe('minutes', 10)
        assert result == "just 10 minutes"

    def test_format_timeframe_negative_delta(self):
        result = self.mock_instance._format_timeframe('days', -7)
        assert result == "7 days ago"

    def test_format_timeframe_zero_delta(self):
        result = self.mock_instance._format_timeframe('days', 0)
        assert result == "in 0 days"

    def test_format_timeframe_large_future_delta(self):
        result = self.mock_instance._format_timeframe('hours', 1000)
        assert result == "in 1000 hours"

    def test_format_timeframe_large_past_delta(self):
        result = self.mock_instance._format_timeframe('days', -1000)
        assert result == "1000 days ago"

    def test_format_timeframe_invalid_timeframe(self):
        with pytest.raises(KeyError):
            self.mock_instance._format_timeframe('invalid', 5)

    def test_format_timeframe_invalid_delta_type(self):
        with pytest.raises(TypeError):
            self.mock_instance._format_timeframe('days', 'five')

