    result = list(count_cycle('AB', 100))
    assert len(result) == 200
    assert result[:4] == [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B')]
    assert result[-4:] == [(99, 'A'), (99, 'B'), (99, 'A'), (99, 'B')]

